[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:DataDownload ;
                    schema1:additionalType "RO-CRATE" ;
                    schema1:contentUrl "https://astromat.org/downloads/adadsc-example-001.zip" ;
                    schema1:description "Archive containing DSC data files and supplementary materials" ;
                    schema1:encodingFormat "application/zip" ;
                    schema1:hasPart <https://example.org/adaDSC-file-001>,
                        <https://example.org/adaDSC-file-002> ;
                    schema1:name "adaDSC-ALH84001-archive.zip" ;
                    schema1:provider [ a schema1:Organization ;
                            schema1:name "Astromat Data Archive" ] ;
                    schema1:size [ a schema1:QuantitativeValue ;
                            schema1:unitText "byte" ;
                            schema1:value 15728640 ] ;
                    ns1:checksum [ a ns1:Checksum ;
                            ns1:algorithm "SHA256" ;
                            ns1:checksumValue "a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2" ] ] ;
            sh:resultMessage "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Recommended: include dcterms:conformsTo to identify the standard or specification this distribution conforms to." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ;
                    sh:severity sh:Info ] ] .

